function objectForEach(object, callback) {
  Object.entries(object).forEach(([key, value]) => {
    callback({ key, value });
  });
}
function objectMap(object, callback) {
  return Object.entries(object).map(([key, value]) => {
    return callback({ key, value });
  });
}
export {
  objectForEach,
  objectMap
};
